    if (nextStatus === 'On The Way') updates.liveCoordinates = { percent: 65 };
    if (nextStatus === 'Near Customer') updates.liveCoordinates = { percent: 88 };
    if (nextStatus === 'Delivered') updates.liveCoordinates = { percent: 100 };

