                            <option value="On The Way">On The Way</option>
                            <option value="Near Customer">Near Customer</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Cancelled">Cancelled</option>
                          </select>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </motion.div>
            )}

            {activeTab === 'earnings' && (
