import { motion } from 'framer-motion';
import { Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { FiHome, FiBox, FiList, FiMessageSquare, FiUser, FiBell, FiLogOut } from 'react-icons/fi';
import { GiSprout } from 'react-icons/gi';
import { useAuth } from '../../context/AuthContext';
import { useProducts } from '../../context/ProductContext';
import { useOrders } from '../../context/OrdersContext';
import { useState, useMemo, useEffect } from 'react';

// Import new modular components
import FarmerDashboardOverview from './FarmerDashboardOverview';
import FarmerProducts from './FarmerProducts';
import FarmerOrders from './FarmerOrders';
import FarmerSupport from './FarmerSupport';
import FarmerProfile from './FarmerProfile';
import { AnimatePresence } from 'framer-motion';

export default function FarmerDashboard() {
  const location = useLocation();
  const { user, logout } = useAuth();
  const { products } = useProducts();
  const { orders, payouts } = useOrders();
  const navigate = useNavigate();
  const handleLogout = () => { logout(); navigate('/'); };

  const [showNotifications, setShowNotifications] = useState(false);
  const [readNotifications, setReadNotifications] = useState([]);

  const isOrderForFarmer = (o, fId) => {
    if (!fId) return false;
    return String(o.farmerId) === String(fId) || 
      (Array.isArray(o.items) && o.items.some(item => String(item.farmerId) === String(fId)));
  };

  // Live Toast for freshly delivered orders
  const [lastDeliveredOrders, setLastDeliveredOrders] = useState(() => {
    return orders.filter(o => o.status === 'Delivered' && isOrderForFarmer(o, user?.id)).map(o => o.id);
  });
  const [deliveryToast, setDeliveryToast] = useState(null);

  useEffect(() => {
    if (!user?.id) return;
    const currentDelivered = orders.filter(o => o.status === 'Delivered' && isOrderForFarmer(o, user?.id));

    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLastDeliveredOrders(prev => {
      const newDelivered = currentDelivered.filter(o => !prev.includes(o.id));
      if (newDelivered.length > 0) {
        const order = newDelivered[0];
        // Defer toast state updates to avoid synchronous setState inside render/effect cycle
        setTimeout(() => {
          setDeliveryToast(order);
          setTimeout(() => setDeliveryToast(null), 6000);
        }, 0);
        return currentDelivered.map(o => o.id);
      }

      const allDeliveredIds = currentDelivered.map(o => o.id);
      // Only update if lists differ to prevent unnecessary state updates
      const hasChanged = allDeliveredIds.length !== prev.length || 
                         allDeliveredIds.some((id, idx) => id !== prev[idx]);
      if (hasChanged) {
        return allDeliveredIds;
      }
      return prev;
    });
  }, [orders, user?.id]);

  const notifications = useMemo(() => {
    const notifs = [];
    const pendingOrders = orders.filter(o => o.status === 'Pending' && isOrderForFarmer(o, user?.id));
    pendingOrders.forEach(o => {
      notifs.push({
        id: `order-${o.id}`,
        title: 'New Order Received',
        message: `Order #${o.id} for ₹${o.total}`,
        time: o.date,
        type: 'order'
      });
    });

    const deliveredOrders = orders.filter(o => o.status === 'Delivered' && isOrderForFarmer(o, user?.id));
    deliveredOrders.forEach(o => {
      notifs.push({
        id: `delivered-${o.id}`,
        title: '🎉 Order is Delivered',
        message: `Order #${o.id} has been delivered to the customer.`,
        time: o.deliveredAt || o.date,
        type: 'delivered'
      });
    });

    const lowStockProducts = products.filter(p => p.farmerId === user?.id && p.stock < 20);
    lowStockProducts.forEach(p => {
      notifs.push({
        id: `stock-${p.id}`,
        title: 'Low Stock Alert',
        message: `Only ${p.stock} ${p.unit} of ${p.name} left.`,
        time: new Date().toISOString(),
        type: 'alert'
      });
    });

    // Dynamic Weekly Payout Notifications
    const farmerPayouts = (payouts?.farmers || []).filter(p => String(p.farmerId) === String(user?.id));
    farmerPayouts.forEach(p => {
      notifs.push({
        id: `payout-${p.id}-${p.status}`,
        title: p.status === 'Paid' ? '💰 Weekly Payout Disbursed!' : '⏳ Payout Pending Approval',
        message: p.status === 'Paid' 
          ? `Your weekly payout of ₹${p.netEarnings.toFixed(2)} has been successfully credited to your bank account.`
          : `Your weekly payout of ₹${p.netEarnings.toFixed(2)} is pending approval for week ending ${p.weekEndDate}.`,
        time: p.createdAt || new Date().toISOString(),
        type: 'payout'
      });
    });

    return notifs.sort((a, b) => new Date(b.time) - new Date(a.time));
  }, [orders, products, user, payouts]);

  const unreadCount = notifications.filter(n => !readNotifications.includes(n.id)).length;

  const navLinks = [
    { path: '/farmer/dashboard', name: 'Dashboard', icon: <FiHome /> },
    { path: '/farmer/products', name: 'Products', icon: <FiBox /> },
    { path: '/farmer/orders', name: 'Orders', icon: <FiList /> },
    { path: '/farmer/support', name: 'Support', icon: <FiMessageSquare /> },
    { path: '/farmer/profile', name: 'Profile', icon: <FiUser /> },
  ];

  if (user && user.role === 'farmer' && user.status !== 'Verified') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-cream relative overflow-hidden p-4">
        {/* Decorative background blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-primary/20 rounded-full blur-3xl" />
        <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-forest/20 rounded-full blur-3xl" />

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="w-full max-w-lg z-10"
        >
          <div className="bg-white/80 backdrop-blur-xl p-8 rounded-3xl shadow-2xl border border-white text-center">
            <div className="text-5xl mb-4 flex justify-center">
              {user.status === 'Pending' && <span className="text-orange-500 animate-pulse">⏳</span>}
              {user.status === 'Suspended' && <span className="text-yellow-500 animate-bounce">⚠️</span>}
              {user.status === 'Rejected' && <span className="text-red-500">❌</span>}
            </div>

            <h2 className="text-3xl font-black text-forest mb-2">
              {user.status === 'Pending' && 'Account Pending Approval'}
              {user.status === 'Suspended' && 'Account Suspended'}
              {user.status === 'Rejected' && 'Registration Rejected'}
            </h2>

            <p className="text-earth text-sm mb-8 leading-relaxed font-medium">
              {user.status === 'Pending' && 'Your farm registration is currently pending review by our administration team. We are verifying your details and will activate your account shortly.'}
              {user.status === 'Suspended' && 'Your farmer account has been temporarily suspended by the administrator. Please reach out to support if you believe this is an error.'}
              {user.status === 'Rejected' && 'Your farmer registration request has been rejected by the administrator. Please contact our support team for more details.'}
            </p>

            <div className="flex gap-4">
              <button 
                onClick={handleLogout} 
                className="flex-1 py-3.5 rounded-2xl bg-gradient-to-r from-forest to-primary text-white font-bold text-base shadow-lg hover:shadow-xl hover:scale-[1.02] transition-all flex items-center justify-center gap-2"
              >
                <FiLogOut /> Logout
              </button>
            </div>
          </div>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-forest text-white flex flex-col hidden md:flex fixed h-full">
        <div className="p-6">
          <div className="flex items-center gap-2 text-2xl font-bold text-white mb-8">
            <span className="text-primary"><GiSprout size={24} /></span> Uzhavar Sandhai
          </div>
        </div>
        <nav className="flex-1 px-4 space-y-2">
          {navLinks.map((link) => (
            <Link 
              key={link.name} 
              to={link.path}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-colors ${location.pathname === link.path || (link.path === '/farmer/dashboard' && location.pathname === '/farmer') ? 'bg-primary text-white' : 'text-cream/70 hover:bg-white/10'}`}
            >
              {link.icon} {link.name}
            </Link>
          ))}
        </nav>
        <div className="p-4 border-t border-white/10">
          <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-red-300 hover:bg-red-500/10 transition-colors">
            <FiLogOut /> Logout
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 md:ml-64 flex flex-col min-h-screen">
        {/* Top Header */}
        <header className="bg-white shadow-sm px-8 py-4 flex justify-between items-center sticky top-0 z-10">
          <h1 className="text-xl font-bold text-forest">Farmer Portal</h1>
          <div className="flex items-center gap-6">
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="relative text-earth hover:text-primary">
                <FiBell size={24} />
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-500 w-4 h-4 rounded-full border-2 border-white flex items-center justify-center text-[8px] text-white font-bold">{unreadCount}</span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden z-50">
                  <div className="p-4 border-b border-gray-100 font-bold text-gray-800 flex justify-between items-center">
                    Notifications
                    <button onClick={() => setReadNotifications(notifications.map(n => n.id))} className="text-xs text-primary font-medium hover:underline">Mark all read</button>
                  </div>
                  <div className="max-h-80 overflow-y-auto">
                    {notifications.length === 0 ? (
                      <div className="p-4 text-center text-gray-500 text-sm">No new notifications</div>
                    ) : (
                      notifications.map(n => (
                        <div key={n.id} onClick={() => !readNotifications.includes(n.id) && setReadNotifications([...readNotifications, n.id])} className={`p-4 border-b border-gray-50 text-sm cursor-pointer hover:bg-gray-50 ${readNotifications.includes(n.id) ? 'bg-white' : 'bg-green-50'}`}>
                          <div className="font-bold text-gray-800">{n.title}</div>
                          <div className="text-gray-600 mt-1">{n.message}</div>
                          <div className="text-xs text-gray-400 mt-2">{new Date(n.time).toLocaleString() !== 'Invalid Date' ? new Date(n.time).toLocaleDateString() : n.time}</div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="p-3 bg-gray-50 text-center border-t border-gray-100">
                    <Link to="/farmer/orders" onClick={() => setShowNotifications(false)} className="text-sm font-bold text-primary hover:underline">View All Orders</Link>
                  </div>
                </div>
              )}
            </div>
            <div className="flex items-center gap-3 border-l pl-6 border-gray-200">
              <img src={user?.image || "https://images.unsplash.com/photo-1595856728032-47d06634b070?w=100&auto=format&fit=crop&fm=webp"} alt="Profile" className="w-10 h-10 rounded-full object-cover"  loading="lazy" decoding="async" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/400x400/eeeeee/999999?text=No+Image"; }} />
              <div className="hidden sm:block">
                <div className="font-bold text-forest text-sm">{user?.name || 'Farmer'}</div>
                <div className="text-xs text-earth">{user?.farmName || 'Your Farm'}</div>
              </div>
            </div>
          </div>
        </header>

        {/* Dynamic Content */}
        <main className="flex-1 p-4 md:p-8 pb-28 md:pb-8">
          <Routes>
            <Route path="/" element={<FarmerDashboardOverview />} />
            <Route path="dashboard" element={<FarmerDashboardOverview />} />
            <Route path="products" element={<FarmerProducts />} />
            <Route path="orders" element={<FarmerOrders />} />
            <Route path="support" element={<FarmerSupport />} />
            <Route path="profile" element={<FarmerProfile />} />
            <Route path="*" element={<div className="text-center py-20 text-earth text-lg">Under Construction for Demo</div>} />
          </Routes>
        </main>

        {/* Floating Delivery Acknowledgement Toast */}
        <AnimatePresence>
          {deliveryToast && (
            <motion.div 
              initial={{ opacity: 0, x: 50, y: 50 }} 
              animate={{ opacity: 1, x: 0, y: 0 }} 
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="fixed bottom-24 md:bottom-8 right-8 z-[100] bg-white rounded-2xl shadow-2xl border border-green-150 p-5 max-w-sm flex gap-4"
            >
              <div className="w-12 h-12 rounded-full bg-green-100 flex items-center justify-center text-2xl flex-shrink-0 text-green-600 animate-bounce">
                🎉
              </div>
              <div>
                <div className="font-bold text-gray-800 text-sm">Order is Delivered</div>
                <p className="text-xs text-gray-600 mt-1 leading-relaxed font-semibold">
                  Order <span className="font-bold text-primary">#{deliveryToast.id}</span> was successfully delivered to the customer.
                </p>
                <button 
                  onClick={() => setDeliveryToast(null)} 
                  className="text-[10px] text-green-700 font-bold uppercase tracking-wider mt-3 block hover:underline"
                >
                  Dismiss
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Mobile Bottom Navigation */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-forest text-white border-t border-white/10 py-2 px-2 flex justify-around items-center z-40 shadow-[0_-2px_10px_rgba(0,0,0,0.15)]">
          {navLinks.map((item) => {
            const isActive = location.pathname === item.path || 
              (item.path === '/farmer/dashboard' && location.pathname === '/farmer');
            return (
              <Link
                key={item.name}
                to={item.path}
                className={`flex flex-col items-center gap-0.5 text-[10px] font-bold transition-all ${isActive ? 'text-primary' : 'text-cream/70 hover:text-white'}`}
              >
                <span className={`p-2 rounded-xl transition-colors ${isActive ? 'bg-primary/20 text-primary' : 'text-cream/70'}`}>
                  {item.icon}
                </span>
                <span className="mt-0.5">{item.name}</span>
              </Link>
            );
          })}
        </nav>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { FiUser, FiMapPin, FiPhone, FiMail, FiEdit3, FiShield, FiSave, FiX, FiCamera, FiStar } from 'react-icons/fi';
import { useAuth } from '../../context/AuthContext';
import { useFarmers } from '../../context/FarmerContext';
import { useProducts } from '../../context/ProductContext';

export default function FarmerProfile() {
  const { user, login } = useAuth();
  const { updateFarmer } = useFarmers();
  const { updateFarmerProducts } = useProducts();
  const [isEditing, setIsEditing] = useState(false);

  const [showPasswordForm, setShowPasswordForm] = useState(false);
  const [passwordData, setPasswordData] = useState({ current: '', new: '', confirm: '' });
  const [passwordMsg, setPasswordMsg] = useState(null);

  const [showBankForm, setShowBankForm] = useState(false);
  const [bankData, setBankData] = useState({ 
    accountName: user?.bankDetails?.accountName || '', 
    accountNumber: user?.bankDetails?.accountNumber || '', 
    ifsc: user?.bankDetails?.ifsc || '' 
  });
  const [bankMsg, setBankMsg] = useState(null);
  const [formData, setFormData] = useState({
    name: user?.name || 'Farmer',
    farmName: user?.farmName || 'Your Farm',
    location: user?.location || 'Tamil Nadu',
    phone: user?.phone || 'Not provided',
    email: user?.email || 'Not provided',
    image: user?.image || 'https://images.unsplash.com/photo-1595856728032-47d06634b070?w=200&auto=format&fit=crop&fm=webp'
  });

  const handleSave = () => {
    const updatedUser = { ...user, ...formData };
    login(updatedUser);
    updateFarmer(user.id, formData);
    updateFarmerProducts(user.id, formData);
    setIsEditing(false);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleProfileImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({ ...formData, image: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const profileData = {
    ...formData,
    joined: 'Jan 2024',
    rating: user?.rating || 4.5,
    certifications: ['FSSAI Certified', '100% Fresh Verified', 'State Agri Board']
  };

  const handlePasswordSubmit = (e) => {
    e.preventDefault();
    if (passwordData.new !== passwordData.confirm) {
      setPasswordMsg({ type: 'error', text: 'New passwords do not match' });
      return;
    }
    if (passwordData.new.length < 6) {
      setPasswordMsg({ type: 'error', text: 'Password must be at least 6 characters' });
      return;
    }
    login({ ...user, password: passwordData.new });
    updateFarmer(user.id, { password: passwordData.new });
    setPasswordMsg({ type: 'success', text: 'Password updated successfully' });
    setPasswordData({ current: '', new: '', confirm: '' });
    setTimeout(() => { setPasswordMsg(null); setShowPasswordForm(false); }, 2000);
  };

  const handleBankSubmit = (e) => {
    e.preventDefault();
    if (!bankData.accountName || !bankData.accountNumber || !bankData.ifsc) {
      setBankMsg({ type: 'error', text: 'All fields are required' });
      return;
    }
    login({ ...user, bankDetails: bankData });
    updateFarmer(user.id, { bankDetails: bankData });
    setBankMsg({ type: 'success', text: 'Bank details updated successfully' });
    setTimeout(() => { setBankMsg(null); setShowBankForm(false); }, 2000);
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-4xl mx-auto">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">My Profile</h2>
        {isEditing ? (
          <div className="flex gap-3">
            <button onClick={() => setIsEditing(false)} className="flex items-center gap-2 bg-white text-red-500 border border-red-200 px-4 py-2 rounded-xl font-bold shadow-sm hover:bg-red-50 transition-colors">
              <FiX /> Cancel
            </button>
            <button onClick={handleSave} className="flex items-center gap-2 bg-primary text-white px-4 py-2 rounded-xl font-bold shadow-sm hover:bg-primary-light transition-colors">
              <FiSave /> Save Changes
            </button>
          </div>
        ) : (
          <button onClick={() => setIsEditing(true)} className="flex items-center gap-2 bg-white text-gray-700 border border-gray-300 px-4 py-2 rounded-xl font-bold shadow-sm hover:bg-gray-50 transition-colors">
            <FiEdit3 /> Edit Profile
          </button>
        )}
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Cover Image */}
        <div className="h-48 bg-gradient-to-r from-primary to-primary-light relative">
          <img src="https://images.unsplash.com/photo-1500937386664-56d1dfef3854?w=1000&auto=format&fit=crop&fm=webp" className="w-full h-full object-cover opacity-50 mix-blend-overlay" alt="Farm Cover"  loading="lazy" decoding="async" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/400x400/eeeeee/999999?text=No+Image"; }} />
          <div className="absolute -bottom-16 left-8">
            <div className={`relative group w-32 h-32 rounded-full border-4 border-white shadow-lg bg-white overflow-hidden ${isEditing ? 'cursor-pointer' : ''}`}>
              <img src={profileData.image || 'https://placehold.co/400x400/eeeeee/999999?text=No+Image'} className="w-full h-full object-cover" alt="Profile"  loading="lazy" decoding="async" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/400x400/eeeeee/999999?text=No+Image"; }} />
              {isEditing && (
                <label className="absolute inset-0 bg-black/50 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer z-10">
                  <FiCamera className="text-white w-6 h-6 mb-1" />
                  <span className="text-white text-[10px] font-bold">CHANGE</span>
                  <input type="file" accept="image/*" className="hidden" onChange={handleProfileImageUpload} />
                </label>
              )}
            </div>
          </div>
        </div>

        <div className="pt-20 px-8 pb-8">
          <div className="flex justify-between items-start mb-8">
            <div className="w-full max-w-lg">
              {isEditing ? (
                <div className="space-y-3">
                  <div>
                    <label className="text-xs text-gray-500 font-bold uppercase">Name</label>
                    <input type="text" name="name" value={formData.name} onChange={handleChange} className="w-full text-xl font-black text-gray-800 bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-primary" />
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 font-bold uppercase">Farm Name</label>
                    <input type="text" name="farmName" value={formData.farmName} onChange={handleChange} className="w-full text-lg font-medium text-primary bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-primary" />
                  </div>
                </div>
              ) : (
                <>
                  <h3 className="text-3xl font-black text-gray-800">{profileData.name}</h3>
                  <div className="text-lg font-medium text-primary mt-1">{profileData.farmName}</div>
                </>
              )}
            </div>
            {!isEditing && (
              <div className="bg-green-100 text-green-700 px-4 py-2 rounded-xl flex items-center gap-2 font-bold shadow-sm">
                <span className="text-xl text-sun fill-current"><FiStar /></span> {profileData.rating} Rating
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Contact Details */}
            <div className="space-y-6">
              <h4 className="text-sm font-black text-gray-400 uppercase tracking-wider">Contact Information</h4>
              <div className="space-y-4">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center text-gray-500"><FiPhone /></div>
                  <div>
                    <div className="text-xs text-gray-500 font-medium">Phone Number</div>
                    {isEditing ? (
                      <input type="tel" name="phone" value={formData.phone} onChange={handleChange} className="font-bold text-gray-800 bg-white border border-gray-200 rounded px-2 py-1 outline-none focus:border-primary w-full mt-1" />
                    ) : (
                      <div className="font-bold text-gray-800">{profileData.phone}</div>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center text-gray-500"><FiMail /></div>
                  <div>
                    <div className="text-xs text-gray-500 font-medium">Email Address</div>
                    {isEditing ? (
                      <input type="email" name="email" value={formData.email} onChange={handleChange} className="font-bold text-gray-800 bg-white border border-gray-200 rounded px-2 py-1 outline-none focus:border-primary w-full mt-1" />
                    ) : (
                      <div className="font-bold text-gray-800">{profileData.email}</div>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center text-gray-500"><FiMapPin /></div>
                  <div className="w-full">
                    <div className="text-xs text-gray-500 font-medium">Farm Address</div>
                    {isEditing ? (
                      <input type="text" name="location" value={formData.location} onChange={handleChange} className="font-bold text-gray-800 bg-white border border-gray-200 rounded px-2 py-1 outline-none focus:border-primary w-full mt-1" />
                    ) : (
                      <div className="font-bold text-gray-800">{profileData.location}</div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Certifications */}
            <div className="space-y-6">
              <h4 className="text-sm font-black text-gray-400 uppercase tracking-wider">Certifications & Badges</h4>
              <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-4">
                {profileData.certifications.map((cert, i) => (
                  <div key={i} className="flex items-center gap-3">
                    <FiShield className="text-primary text-xl" />
                    <span className="font-bold text-gray-700">{cert}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Account Settings */}
          <div className="mt-12 pt-8 border-t border-gray-100">
            <h4 className="text-sm font-black text-gray-400 uppercase tracking-wider mb-6">Account Settings</h4>
            <div className="flex flex-wrap gap-4 mb-6">
              <button onClick={() => { setShowPasswordForm(!showPasswordForm); setShowBankForm(false); }} className={`px-6 py-2.5 rounded-xl font-bold transition-colors ${showPasswordForm ? 'bg-primary text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}>Change Password</button>
              <button onClick={() => { setShowBankForm(!showBankForm); setShowPasswordForm(false); }} className={`px-6 py-2.5 rounded-xl font-bold transition-colors ${showBankForm ? 'bg-primary text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}>Update Bank Details</button>
            </div>

            {showPasswordForm && (
              <form onSubmit={handlePasswordSubmit} className="bg-gray-50 p-6 rounded-2xl border border-gray-200 max-w-md animate-fade-in space-y-4">
                <h5 className="font-bold text-gray-800">Change Password</h5>
                {passwordMsg && <div className={`text-sm font-bold p-2 rounded ${passwordMsg.type === 'error' ? 'text-red-600 bg-red-100' : 'text-green-600 bg-green-100'}`}>{passwordMsg.text}</div>}
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Current Password</label>
                  <input type="password" value={passwordData.current} onChange={e => setPasswordData({...passwordData, current: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">New Password</label>
                  <input type="password" value={passwordData.new} onChange={e => setPasswordData({...passwordData, new: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Confirm New Password</label>
                  <input type="password" value={passwordData.confirm} onChange={e => setPasswordData({...passwordData, confirm: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <button type="submit" className="w-full bg-primary text-white font-bold py-2 rounded-lg hover:bg-primary-light">Update Password</button>
              </form>
            )}

            {showBankForm && (
              <form onSubmit={handleBankSubmit} className="bg-gray-50 p-6 rounded-2xl border border-gray-200 max-w-md animate-fade-in space-y-4">
                <h5 className="font-bold text-gray-800">Bank Details</h5>
                {bankMsg && <div className={`text-sm font-bold p-2 rounded ${bankMsg.type === 'error' ? 'text-red-600 bg-red-100' : 'text-green-600 bg-green-100'}`}>{bankMsg.text}</div>}
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Account Holder Name</label>
                  <input type="text" value={bankData.accountName} onChange={e => setBankData({...bankData, accountName: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Account Number</label>
                  <input type="text" value={bankData.accountNumber} onChange={e => setBankData({...bankData, accountNumber: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">IFSC Code</label>
                  <input type="text" value={bankData.ifsc} onChange={e => setBankData({...bankData, ifsc: e.target.value})} className="w-full px-3 py-2 rounded-lg border border-gray-300" required />
                </div>
                <button type="submit" className="w-full bg-primary text-white font-bold py-2 rounded-lg hover:bg-primary-light">Save Bank Details</button>
              </form>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export const printInvoice = (order, userDetails) => {
  const printWindow = window.open('', '_blank', 'width=800,height=900');
  if (!printWindow) {
    alert("Please allow popups to print invoices");
    return;
  }

  const formatDate = (dateStr) => {
    if (!dateStr) return new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    try {
      const d = new Date(dateStr);
      if (isNaN(d.getTime())) return new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    } catch (e) {
      return new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    }
  };

  const getQtyNumber = (item) => {
    const raw = item.quantity !== undefined ? item.quantity : item.qty;
    if (typeof raw === 'number') return raw;
    if (typeof raw === 'string') {
      const parsed = parseFloat(raw);
      return isNaN(parsed) ? 1 : parsed;
    }
    return 1;
  };

  const getQtyDisplay = (item) => {
    const raw = item.qty !== undefined ? item.qty : item.quantity;
    if (!raw) return '1 KG';
    const str = String(raw).trim();
    const lower = str.toLowerCase();
    if (lower.includes('kg') || lower.includes('g') || lower.includes('unit') || lower.includes('packet')) {
      return str.toUpperCase();
    }
    return `${str} KG`;
  };

  const items = Array.isArray(order.items) ? order.items : (order.itemsList || []);
  const itemsRows = items.map((item, index) => {
    const qtyNum = getQtyNumber(item);
    const qtyDisplay = getQtyDisplay(item);
    const priceNum = parseFloat(item.price) || 0;
    const itemTotal = priceNum * qtyNum;
    const farmName = item.farmerName || item.farmer || order.farmer || 'Uzhavar Verified Farm';
    return `
      <tr>
        <td>${index + 1}</td>
        <td style="text-align: left; font-weight: bold; padding-left: 20px;">
          ${item.name}
          <div style="font-size: 11px; color: #666; font-weight: normal; margin-top: 4px;">Producer: ${farmName}</div>
        </td>
        <td>₹${priceNum.toFixed(2)} x ${qtyDisplay}</td>
        <td style="font-weight: bold;">₹${itemTotal.toFixed(2)}</td>
      </tr>
    `;
  }).join('');

  // Use exact amounts stored on the order object to guarantee 100% consistency with Checkout/Dashboard
  const subtotal = order.subtotal !== undefined ? order.subtotal : items.reduce((acc, item) => acc + (parseFloat(item.price) || 0) * getQtyNumber(item), 0);
  const discountAmount = order.discount !== undefined ? order.discount : 0;
  const deliveryCharge = order.deliveryFee !== undefined ? order.deliveryFee : 0;
  const platformFee = 10.00;
  const gstAmount = parseFloat((subtotal * 0.05).toFixed(2));
  const grandTotal = order.total !== undefined ? order.total : (subtotal - discountAmount + deliveryCharge + platformFee + gstAmount);

  const htmlContent = `
    <!DOCTYPE html>
    <html lang="en">
    <head>
      <meta charset="UTF-8">
      <meta name="viewport" content="width=device-width, initial-scale=1.0">
      <title>Invoice #${order.id} - Uzhavar Sandhai</title>
      <style>
        * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
          font-family: Arial, sans-serif;
        }
        body {
          background: #e8e8e8;
          padding: 40px;
          -webkit-print-color-adjust: exact;
          print-color-adjust: exact;
        }
        .invoice-container {
          max-width: 1000px;
          margin: auto;
          background: #f8f8f8;
          padding: 50px;
          position: relative;
          overflow: hidden;
          box-shadow: 0 0 15px rgba(0,0,0,.1);
        }
        .top-wave,
        .bottom-wave {
          position: absolute;
          left: -10%;
          width: 120%;
          height: 130px;
          background: linear-gradient(135deg, #8ee88e, #d3ffd3);
          border-radius: 50%;
        }
        .top-wave {
          top: -80px;
        }
        .bottom-wave {
          bottom: -80px;
        }
        .header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 50px;
          position: relative;
          z-index: 10;
        }
        .invoice-info {
          margin-top: 40px;
        }
        .invoice-info p {
          margin-bottom: 8px;
          font-size: 15px;
        }
        .header h1 {
          font-size: 65px;
          font-weight: bold;
          color: #00c853;
        }
        .details {
          display: flex;
          justify-content: space-between;
          margin-bottom: 40px;
          position: relative;
          z-index: 10;
        }
        .details h3 {
          margin-bottom: 15px;
          font-size: 18px;
          color: #00c853;
        }
        .details p {
          margin-bottom: 8px;
          font-size: 14px;
        }
        table {
          width: 100%;
          border-collapse: collapse;
          margin-bottom: 30px;
          background: white;
          position: relative;
          z-index: 10;
        }
        thead {
          background: #00c853;
          color: white;
        }
        th {
          padding: 15px;
          letter-spacing: 3px;
          font-size: 14px;
          text-transform: uppercase;
        }
        td {
          padding: 15px;
          border-bottom: 1px solid #ddd;
          text-align: center;
          font-size: 14px;
        }
        .summary {
          display: flex;
          flex-direction: column;
          align-items: flex-end;
          gap: 20px;
          position: relative;
          z-index: 10;
        }
        .totals-box {
          width: 350px;
          padding: 20px;
          border: 1px solid #ccc;
          background: white;
        }
        .totals-box p {
          display: flex;
          justify-content: space-between;
          margin-bottom: 15px;
          font-size: 14px;
        }
        .grand-total {
          width: 350px;
          padding: 20px;
          background: #00c853;
          color: white;
          font-size: 28px;
          font-weight: bold;
          display: flex;
          justify-content: space-between;
        }
        .terms {
          margin-top: 50px;
          position: relative;
          z-index: 10;
        }
        .terms h3 {
          margin-bottom: 15px;
          color: #00c853;
        }
        .terms p {
          font-size: 13px;
          line-height: 1.5;
          color: #555;
        }
        @media print {
          body {
            background: #fff;
            padding: 0;
          }
          .invoice-container {
            box-shadow: none;
            padding: 20px 0;
            width: 100%;
            max-width: 100%;
          }
        }
      </style>
    </head>
    <body>
      <div class="invoice-container">
        <div class="top-wave"></div>
        <div class="header">
          <div class="invoice-info">
            <p><strong>Invoice Number:</strong> <span>${order.id}</span></p>
            <p><strong>Date:</strong> <span>${formatDate(order.createdAt || order.created_at)}</span></p>
          </div>
          <h1>INVOICE</h1>
        </div>

        <div class="details">
          <div>
            <h3>BILL TO:</h3>
            <p><b>${userDetails?.fullName || userDetails?.name || order.customerName || 'Valued Customer'}</b></p>
            <p>${userDetails?.address || order.shippingAddress || order.address || 'Uzhavar Delivery Zone'}</p>
            <p>${userDetails?.city || order.city || 'Tamil Nadu'}</p>
          </div>
          <div>
            <h3>PAYMENT INFORMATION:</h3>
            <p><strong>Bank (Method):</strong> <span>${order.deliveryDetails?.paymentMethod || order.paymentMethod || 'Cash on Delivery'}</span></p>
            <p><strong>Name:</strong> <span>${userDetails?.fullName || userDetails?.name || order.customerName || 'Valued Customer'}</span></p>
            <p><strong>Account (Status):</strong> <span>${order.paymentStatus === 'Paid' ? 'Paid Online' : 'Cash Collection'}</span></p>
          </div>
        </div>

        <table>
          <thead>
            <tr>
              <th>ITEM</th>
              <th>DESCRIPTION</th>
              <th>RATE</th>
              <th>AMOUNT</th>
            </tr>
          </thead>
          <tbody>
            ${itemsRows}
          </tbody>
        </table>

        <div class="summary">
          <div class="totals-box">
            <p>
              <span>Sub Total:</span>
              <span>₹${subtotal.toFixed(2)}</span>
            </p>
            ${discountAmount > 0 ? `
              <p style="color: #00c853; font-weight: bold;">
                <span>Bulk Discount:</span>
                <span>- ₹${discountAmount.toFixed(2)}</span>
              </p>
            ` : ''}
            <p>
              <span>Delivery Charge:</span>
              <span>₹${deliveryCharge.toFixed(2)}</span>
            </p>
            <p>
              <span>Platform Fee:</span>
              <span>₹${platformFee.toFixed(2)}</span>
            </p>
            <p>
              <span>GST (5%):</span>
              <span>₹${gstAmount.toFixed(2)}</span>
            </p>
          </div>
          <div class="grand-total">
            <span>TOTAL:</span>
            <span>₹${grandTotal.toFixed(2)}</span>
          </div>
        </div>

        <div class="terms">
          <h3>TERM AND CONDITIONS:</h3>
          <p>Thank you for buying direct and supporting our local farm community! 🌱 This is a computer generated invoice and requires no signature. Payment is subject to standard terms of purchase.</p>
        </div>
        <div class="bottom-wave"></div>
      </div>

      <script>
        window.onload = function() {
          window.print();
        }
      </script>
    </body>
    </html>
  `;

  printWindow.document.write(htmlContent);
  printWindow.document.close();
};
